  const adapters = new Map<string, RuntimeAdapter>([
    ["fake", new FakeRuntimeAdapter()],
    ["codex", new CodexExecJsonAdapter({ modelCatalog: codexProbe.models })]
  ]);
  const eventBus = new EventBus();
  const runner = new RuntimeRunnerService({
    adapters,
    eventBus,
    ...stores
  });
